
import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Button from '../../components/base/Button';
import Card from '../../components/base/Card';
import Header from '../../components/feature/Header';
import { supabase } from '../../supabaseClient';

interface HistoryItem {
  id: string;
  date: string;
  role?: {
    id: string;
    name: string;
    icon: string;
    description: string;
    color: string;
  };
  concern?: string;
  fortune: string;
}

export default function PastConcernsPage() {
  const navigate = useNavigate();
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [selectedItem, setSelectedItem] = useState<HistoryItem | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 5;
  
  // Supabase에서 실제 기록 로드
  useEffect(() => {
    (async () => {
      try {
        const { data: auth } = await supabase.auth.getUser();
        const uid = auth?.user?.id;
        if (!uid) { setHistory([]); setIsLoading(false); return; }
        const { data, error } = await supabase
          .from('ai_answers')
          .select('id, created_at, persona, concern, ai_response')
          .eq('user_id', uid)
          .order('created_at', { ascending: false });
        if (error) throw error;
        const mapped: HistoryItem[] = (data || []).map((row: any) => ({
          id: row.id,
          date: row.created_at,
          concern: row.concern,
          fortune: row.ai_response,
        }));
        setHistory(mapped);
      } catch {
        setHistory([]);
      } finally {
        setIsLoading(false);
      }
    })();
  }, []);
  
  // 페이지네이션 계산
  const totalPages = Math.ceil(history.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentItems = history.slice(startIndex, endIndex);
  
  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffTime = Math.abs(now.getTime() - date.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    
    if (diffDays === 1) return '어제';
    if (diffDays === 2) return '그저께';
    if (diffDays <= 7) return `${diffDays}일 전`;
    
    return date.toLocaleDateString('ko-KR', { 
      month: 'long', 
      day: 'numeric' 
    });
  };
  
  const handleDeleteItem = (id: string) => {
    const updatedHistory = history.filter(item => item.id !== id);
    setHistory(updatedHistory);
    localStorage.setItem('fortuneHistory', JSON.stringify(updatedHistory));
    setSelectedItem(null);
    
    // 현재 페이지에 아이템이 없으면 이전 페이지로
    const newTotalPages = Math.ceil(updatedHistory.length / itemsPerPage);
    if (currentPage > newTotalPages && newTotalPages > 0) {
      setCurrentPage(newTotalPages);
    }
  };
  
  const handleClearAll = () => {
    if (confirm('모든 기록을 삭제하시겠습니까?')) {
      setHistory([]);
      localStorage.removeItem('fortuneHistory');
      setSelectedItem(null);
      setCurrentPage(1);
    }
  };
  
  const handlePageChange = (page: number) => {
    setCurrentPage(page);
    setSelectedItem(null); // 페이지 변경시 선택 해제
  };
  
  if (isLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-amber-200 to-orange-200">
        <Header />
        <div className="flex items-center justify-center min-h-screen">
          <div className="text-center">
            <div className="animate-spin rounded-full h-12 w-12 border-4 border-amber-400 border-t-transparent mx-auto mb-4"></div>
            <p className="text-amber-600">기록을 불러오는 중...</p>
          </div>
        </div>
      </div>
    );
  }
  
  return (
    <div className="min-h-screen bg-gradient-to-br from-amber-200 to-orange-200">
      <Header />
      
      <div className="container mx-auto px-4 py-8 max-w-4xl">
        {/* 페이지 헤더 */}
        <div className="flex justify-between items-center mb-8">
          <div>
            <h1 className="text-3xl font-bold text-gray-800 mb-2">과거 운세 기록</h1>
            <p className="text-gray-600">지금까지 받은 운세들을 다시 확인해보세요</p>
          </div>
          
          {history.length > 0 && (
            <div className="flex space-x-2">
              <Button
                variant="outline"
                size="sm"
                onClick={handleClearAll}
              >
                전체 삭제
              </Button>
              <Button
                size="sm"
                onClick={() => navigate('/role-select')}
              >
                새 운세 보기
              </Button>
            </div>
          )}
        </div>
        
        {history.length === 0 ? (
          /* 빈 상태 */
          <Card className="p-12 text-center">
            <div className="text-6xl mb-4">🥠</div>
            <h3 className="text-xl font-bold text-gray-800 mb-2">아직 운세 기록이 없어요</h3>
            <p className="text-gray-600 mb-6">첫 번째 운세를 받아보시겠어요?</p>
            <Button onClick={() => navigate('/role-select')}>
              운세 받기 시작하기
            </Button>
          </Card>
        ) : (
          /* 기록 목록 */
          <div className="grid md:grid-cols-2 gap-6">
            {/* 왼쪽: 목록 */}
            <div className="space-y-4">
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-lg font-bold text-gray-800">
                  기록 목록 ({history.length}개)
                </h2>
                
                {totalPages > 1 && (
                  <div className="flex items-center space-x-1">
                    <button
                      onClick={() => handlePageChange(currentPage - 1)}
                      disabled={currentPage === 1}
                      className="w-8 h-8 flex items-center justify-center rounded-full bg-white text-gray-400 hover:text-amber-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors duration-300"
                    >
                      <i className="ri-arrow-left-s-line"></i>
                    </button>
                    
                    <span className="text-sm text-gray-600 px-2">
                      {currentPage} / {totalPages}
                    </span>
                    
                    <button
                      onClick={() => handlePageChange(currentPage + 1)}
                      disabled={currentPage === totalPages}
                      className="w-8 h-8 flex items-center justify-center rounded-full bg-white text-gray-400 hover:text-amber-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors duration-300"
                    >
                      <i className="ri-arrow-right-s-line"></i>
                    </button>
                  </div>
                )}
              </div>
              
              {currentItems.map((item) => (
                <Card
                  key={item.id}
                  hover
                  className={`p-4 cursor-pointer transition-all duration-300 ${
                    selectedItem?.id === item.id ? 'ring-2 ring-amber-300 shadow-lg' : ''
                  }`}
                  onClick={() => setSelectedItem(item)}
                >
                  <div className="flex items-start space-x-3">
                    {item.role && (
                      <div className={`w-10 h-10 rounded-full bg-gradient-to-r ${item.role.color} flex items-center justify-center text-white shadow-md flex-shrink-0`}>
                        <i className={item.role.icon}></i>
                      </div>
                    )}
                    
                    <div className="flex-1 min-w-0">
                      <div className="flex justify-between items-start mb-1">
                        <h3 className="font-medium text-gray-800">
                          {item.role?.name || '일반 상담'}
                        </h3>
                        <span className="text-xs text-gray-500 flex-shrink-0 ml-2">
                          {formatDate(item.date)}
                        </span>
                      </div>
                      
                      <p className="text-sm text-gray-600 line-clamp-2 mb-2">
                        {item.concern || '상담 내용'}
                      </p>
                      
                      <p className="text-xs text-amber-600 line-clamp-1">
                        "{item.fortune}"
                      </p>
                    </div>
                  </div>
                </Card>
              ))}
              
              {/* 페이지네이션 하단 */}
              {totalPages > 1 && (
                <div className="flex justify-center mt-6">
                  <div className="flex items-center space-x-2">
                    {Array.from({ length: totalPages }, (_, i) => i + 1).map((page) => (
                      <button
                        key={page}
                        onClick={() => handlePageChange(page)}
                        className={`w-8 h-8 flex items-center justify-center rounded-full text-sm font-medium transition-all duration-300 ${
                          currentPage === page
                            ? 'bg-amber-500 text-white shadow-md'
                            : 'bg-white text-gray-600 hover:bg-amber-100 hover:text-amber-600'
                        }`}
                      >
                        {page}
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            
            {/* 오른쪽: 상세 내용 */}
            <div className="sticky top-8">
              {selectedItem ? (
                <Card className="p-6">
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex items-center space-x-3">
                      {selectedItem.role && (
                        <div className={`w-12 h-12 rounded-full bg-gradient-to-r ${selectedItem.role.color} flex items-center justify-center text-white shadow-lg`}>
                          <i className={selectedItem.role.icon}></i>
                        </div>
                      )}
                      <div>
                        <h3 className="font-bold text-gray-800">
                          {selectedItem.role?.name || '일반 상담'}
                        </h3>
                        <p className="text-sm text-gray-600">
                          {formatDate(selectedItem.date)}
                        </p>
                      </div>
                    </div>
                    
                    <button
                      onClick={() => handleDeleteItem(selectedItem.id)}
                      className="w-8 h-8 flex items-center justify-center rounded-full bg-red-50 text-red-500 hover:bg-red-100 transition-colors duration-300"
                    >
                      <i className="ri-delete-bin-line text-sm"></i>
                    </button>
                  </div>
                  
                  {selectedItem.concern && (
                    <div className="mb-6">
                      <h4 className="font-medium text-gray-800 mb-2">고민 내용</h4>
                      <div className="bg-gray-50 p-4 rounded-lg">
                        <p className="text-gray-700 leading-relaxed">
                          {selectedItem.concern}
                        </p>
                      </div>
                    </div>
                  )}
                  
                  <div>
                    <h4 className="font-medium text-gray-800 mb-2">받은 조언</h4>
                    <div className="bg-gradient-to-br from-amber-200 to-orange-200 p-4 rounded-lg border border-amber-100">
                      <p className="text-gray-800 leading-relaxed font-medium">
                        "{selectedItem.fortune}"
                      </p>
                    </div>
                  </div>
                  
                  <div className="mt-6 pt-4 border-t border-gray-100">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => navigate('/role-select')}
                      className="w-full"
                    >
                      비슷한 고민으로 새 운세 받기
                    </Button>
                  </div>
                </Card>
              ) : (
                <div className="h-40"></div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
